// Combine all report sections into a structured input for the exec summary
const sections = $input.all().map(item => item.json);

// Build structured content
const sectionOrder = [
  'approach', 'strengths', 'development', 'values',
  'top_career_1', 'top_career_2', 'top_career_3',
  'runner_ups', 'outside_box', 'dream_jobs', 'chat_highlights'
];

const sectionLabels = {
  'approach': 'Work Approach',
  'strengths': 'Core Strengths',
  'development': 'Development Areas',
  'values': 'Career Values',
  'top_career_1': 'Top Career Match 1',
  'top_career_2': 'Top Career Match 2',
  'top_career_3': 'Top Career Match 3',
  'runner_ups': 'Runner-Up Careers',
  'outside_box': 'Outside-the-Box Careers',
  'dream_jobs': 'Dream Job Analysis',
  'chat_highlights': 'Chat Discussion Highlights'
};

// Build a map for quick lookup
const sectionMap = {};
sections.forEach(s => {
  sectionMap[s.section_type] = s;
});

let combinedContent = '';

for (const sType of sectionOrder) {
  const s = sectionMap[sType];
  if (!s) continue;

  const label = sectionLabels[sType] || sType;
  combinedContent += `\n## ${label}\n`;

  if (s.title) {
    combinedContent += `Title: ${s.title}\n`;
  }

  // Add the main content (truncated to key points for summary)
  const content = (s.content || '').substring(0, sType === 'chat_highlights' ? 6000 : 2000);
  combinedContent += `${content}\n`;

  // Include user feedback if any
  if (s.feedback && s.feedback !== 'User confirmed section is accurate, no changes needed.' && s.feedback !== 'User confirmed accuracy, no changes needed.') {
    combinedContent += `\nUser Feedback: ${s.feedback}\n`;
  }

  // Include exploration content if any
  if (s.explore) {
    combinedContent += `\nAdditional Discussion: ${s.explore.substring(0, 500)}\n`;
  }

  combinedContent += '\n---\n';
}

// Get report_id from upstream
const reportId = $('Extract report_id').item.json.report_id;
// Language: report_sections carry the language WF1 stamped. Use the first
// section that has one; default English for legacy reports.
const lang = (sections.find(s => s.language) || {}).language || 'en';

return [{
  json: {
    report_id: reportId,
    combined_sections: combinedContent,
    section_count: sections.length,
    preferred_language: lang
  }
}];

const text = $json.text;

if (!text) {
  throw new Error('Executive summary generation returned empty content');
}

const lang = $('Combine Sections').item.json.preferred_language || 'en';

return [{
  json: {
    report_id: $('Extract report_id').item.json.report_id,
    section_type: 'exec_summary',
    title: lang === 'nl' ? 'Samenvatting' : 'Executive Summary',
    content: text,
    order_number: 0,
    language: lang
  }
}];
